import{_ as e,o as t,c as o,ag as r}from"./chunks/framework.HKmjcgbP.js";const c=JSON.parse('{"title":"其他","description":"","frontmatter":{},"headers":[],"relativePath":"其他/其他.md","filePath":"其他/其他.md","lastUpdated":1680514267000}'),l={name:"其他/其他.md"};function i(p,a,n,s,d,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h1><h2 id="devops" tabindex="-1">DevOps <a class="header-anchor" href="#devops" aria-label="Permalink to &quot;DevOps&quot;">​</a></h2><p>DevOps是Development和Operations的组合，是一种方法论，是一组过程、方法与系统的统称，用于促进应用开发、应用运维和质量保障（QA）部门之间的沟通、协作与整合。以期打破传统开发和运营之间的壁垒和鸿沟。</p><h3 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h3><p>持续集成（CI）是在源代码变更后自动检测、拉取、构建和（在大多数情况下）进行单元测试的过程。CI 的目标是将集成简化成一个简单、易于重复的日常开发任务， 这样有助于降低总体的构建成本并在开发周期的早期发现缺陷。</p><p>CD是<strong>持续交付Continuous Delivery</strong>和<strong>持续部署Continuous Deployment</strong>。</p><p>蓝绿发布：简单理解就是流量切换，依据热备的思想，冗余部署服务新版本。</p><p>滚动发布：在升级过程中，并不一下子启动所有新版本，是先启动一台新版本，再停止一台老版本，然后再启动一台新版本，再停止一台老版本，直到升级完成。</p><p>A/B 测试：简单理解就是根据请求内容（header、cookie）将请求流量路由到服务的不同版本。用来测试应用功能表现的方法，例如可用性、受欢迎程度、可见性等等。</p><p>金丝雀发布：也叫灰度发布，是一种基于流量比例的发布策略，部署一个或者一小批新版本的服务，将少量（比如 1%）的请求引流到新版本，逐步调大流量比重，直到所有用户流量都被切换新版本为止。起源是，矿井工人发现，金丝雀对瓦斯气体很敏感，矿工会在下井之前，先放一只金丝雀到井中，如果金丝雀不叫了，就代表瓦斯浓度高。</p><h2 id="开源协议" tabindex="-1">开源协议 <a class="header-anchor" href="#开源协议" aria-label="Permalink to &quot;开源协议&quot;">​</a></h2><p><img src="https://pdai.tech/images/dev_opensource_1.png" alt="img"></p><h2 id="等级保护" tabindex="-1">等级保护 <a class="header-anchor" href="#等级保护" aria-label="Permalink to &quot;等级保护&quot;">​</a></h2><p>为什么是做等级保护？</p><ul><li><p>法律法规要求</p></li><li><p>行业要求</p></li><li><p>企业系统安全的需求</p></li></ul><p>等级保护分为哪些等级</p><ul><li><strong>第一级 自主保护级</strong>：</li></ul><p>（无需备案，对测评周期无要求）此类信息系统受到破坏后，会对公民、法人和其他组织的合法权益造成一般损害，不损害国家安全、社会秩序和公共利益。</p><ul><li><strong>第二级 指导保护级</strong>:</li></ul><p>（公安部门备案，建议两年测评一次）此类信息系统受到破坏后，会对公民、法人和其他组织的合法权益造成严重损害。会对社会秩序、公共利益造成一般损害，不损害国家安全。</p><ul><li><strong>第三级 监督保护级</strong>：</li></ul><p>（公安部门备案，要求每年测评一次）此类信息系统受到破坏后，会对国家安全、社会秩序造成损害，对公共利益造成严重损害，对公民、法人和其他组织的合法权益造成特别严重的损害。</p><ul><li><strong>第四级 强制保护级</strong>：</li></ul><p>（公安部门备案，要求半年一次）此类信息系统受到破坏后，会对国家安全造成严重损害，对社会秩序、公共利益造成特别严重损害。</p><ul><li><strong>第五级 专控保护级</strong>：</li></ul><p>（公安部门备案，依据特殊安全需求进行）此类信息系统受到破坏后会对国家安全造成特别严重损害。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2>',27)])])}const _=e(l,[["render",i]]);export{c as __pageData,_ as default};
